const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const budgets = allOf('Fetch Budgets');
const spendRows = allOf('Fetch MTD Spend');
const spendByService = {};
let totalSpend = 0;
spendRows.forEach(function (r) { const c = parseInt(r.spend_cents) || 0; spendByService[r.service_name] = (spendByService[r.service_name] || 0) + c; totalSpend += c; });
const alerts = [];
budgets.forEach(function (b) {
  // Special case: total_platform compares against summed spend across ALL services.
  const spent = (b.service_name === 'total_platform') ? totalSpend : (spendByService[b.service_name] || 0);
  const pct = b.monthly_limit_cents > 0 ? (spent * 100 / b.monthly_limit_cents) : 0;
  const detail = { service: b.service_name, monthly_limit_cents: b.monthly_limit_cents, mtd_spend_cents: spent, percent_used: Math.round(pct * 10) / 10 };
  if (pct >= (b.auto_pause_pct || 90)) {
    alerts.push({ severity: 'emergency', alert_type: 'cost_auto_pause', title: '[' + b.service_name + '] ' + Math.round(pct) + '% of monthly cap — AUTO PAUSE THRESHOLD', message: 'Month-to-date spend on ' + b.service_name + ' has hit the auto-pause threshold. Non-essential workflows will be paused.', aggregation_key: 'cost:' + b.service_name + ':auto_pause:' + new Date().toISOString().slice(0,7), details: detail });
  } else if (pct >= (b.critical_pct || 75)) {
    alerts.push({ severity: 'critical',  alert_type: 'cost_threshold',  title: '[' + b.service_name + '] ' + Math.round(pct) + '% of monthly cap — CRITICAL',        message: 'Month-to-date spend has crossed the critical threshold.',           aggregation_key: 'cost:' + b.service_name + ':critical:' + new Date().toISOString().slice(0,7),  details: detail });
  } else if (pct >= (b.warning_pct || 50)) {
    alerts.push({ severity: 'warning',   alert_type: 'cost_threshold',  title: '[' + b.service_name + '] ' + Math.round(pct) + '% of monthly cap — warning',          message: 'Month-to-date spend has crossed the warning threshold.',            aggregation_key: 'cost:' + b.service_name + ':warning:' + new Date().toISOString().slice(0,7),   details: detail });
  }
});
return { json: { alerts, evaluated: budgets.length } };

